revision.text:
{{#ifeq:{{ff}}|Template
    | {{Ombox
       | type = style
       | image = [[File:Ambox warning yellow.svg|40x40px|alt=|link=]]
       | text = '''This template is a customized [[Wikipedia:Wrapper templates|wrapper]] for {{tl|Infobox person}}'''. Any field from {{tld|Infobox person}} can work{{#if:{{{wrapped|}}}||&#32;so long as it is added to this template first}}. It will also emit the same [[hCard]] and [[Geo (microformat)|Geo]] [[microformat]]s as {{tld|Infobox person}}. Questions? Just ask [[Template talk:{{BASEPAGENAME}}|here]] or over at [[Template talk:Infobox person]].
      }}<!--
   -->{{#if:{{{main|}}}
       | {{Ombox |text=This infobox wraps the [[Template:{{{main}}}|{{{main}}} template]]. See [[Template:{{{main}}}/doc]] for additional documentation.}}
      }}<!--
   --><includeonly>{{#ifeq:{{PAGENAME}}|{{BASEPAGENAME}} |[[Category:Templates calling Infobox person|{{Remove first word|{{PAGENAME}}}}]]}}</includeonly><!--
-->}}<noinclude>
{{Documentation}}
</noinclude>

